                        const std::string& /*target_xds_authority*/) override {
    return std::make_unique<DeltaSubscriptionState>(type_url, callbacks, dispatcher_,
                                                    xds_config_tracker);
  }

private:
  Event::Dispatcher& dispatcher_;
};

} // namespace XdsMux
} // namespace Config
} // namespace Envoy

