    24→  void insert(ShutdownableMux* mux) { muxes_.insert(mux); }
    25→
    26→  void erase(ShutdownableMux* mux) { muxes_.erase(mux); }
    27→
    28→  void shutdownAll() {
    29→    for (auto& mux : muxes_) {
    30→      mux->shutdown();
    31→    }
    32→  }
    33→
    34→private:
    35→  absl::flat_hash_set<ShutdownableMux*> muxes_;
    36→};
    37→using AllMuxes = ThreadSafeSingleton<AllMuxesState>;
    38→} // namespace
