    54→      xds_resources_delegate_(grpc_mux_context.xds_resources_delegate_),
    55→      eds_resources_cache_(std::move(grpc_mux_context.eds_resources_cache_)),
    56→      target_xds_authority_(grpc_mux_context.target_xds_authority_) {
